}

#[derive(Subcommand)]
enum Commands {
    Workers {
        #[command(subcommand)]
        action: WorkerAction,
    },
}

#[derive(Subcommand)]
enum WorkerAction {
    Probe {
        #[arg(add = ArgValueCompleter::new(worker_completer))]
        worker: Option<String>,
    },
}
