### Worker ID Completer

```rust
// rch/src/completions.rs
use clap_complete::CompletionCandidate;
use std::ffi::OsStr;

/// Complete worker IDs from the config file
pub fn complete_worker_ids(current: &OsStr) -> Vec<CompletionCandidate> {
    let current = current.to_string_lossy();

    // Try to load config from default location
    let config_path = match crate::config::default_config_path() {
        Some(p) => p,
        None => return vec![],
    };

    let config = match crate::config::load_config(&config_path) {
        Ok(c) => c,
        Err(_) => return vec![],
    };

    config
        .workers
        .keys()
        .filter(|id| id.starts_with(current.as_ref()))
        .map(|id| {
            let worker = &config.workers[id];
            CompletionCandidate::new(id.clone())
                .help(Some(format!("{}@{}", worker.user, worker.host).into()))
        })
        .collect()
}

/// Complete toolchain names
pub fn complete_toolchains(current: &OsStr) -> Vec<CompletionCandidate> {
    let current = current.to_string_lossy();

    // Common Rust toolchains
    let toolchains = [
        ("stable", "Latest stable release"),
        ("beta", "Beta channel"),
        ("nightly", "Nightly channel"),
        ("1.75.0", "Specific version"),
        ("1.74.0", "Specific version"),
    ];

    toolchains
        .iter()
        .filter(|(name, _)| name.starts_with(current.as_ref()))
        .map(|(name, desc)| {
            CompletionCandidate::new(*name)
                .help(Some((*desc).into()))
        })
        .collect()
}

/// Complete log levels
pub fn complete_log_levels(current: &OsStr) -> Vec<CompletionCandidate> {
    let current = current.to_string_lossy();

    ["error", "warn", "info", "debug", "trace"]
        .iter()
        .filter(|level| level.starts_with(current.as_ref()))
        .map(|level| CompletionCandidate::new(*level))
        .collect()
}
```

